26	export class BayesApiError extends Error {
27	  constructor(
28	    public status: number,
29	    public code: string,
30	    public details: Record<string, unknown> = {},
31	  ) {
32	    super(`${code}: ${status}`);
33	    this.name = "BayesApiError";
34	  }
35	}
36	
37	async function request<T>(
38	  path: string,
39	  options: RequestInit = {},
40	  session?: Session,
41	): Promise<T> {
42	  const headers: Record<string, string> = {
43	    ...(options.headers as Record<string, string>),
44	  };
45	
46	  if (options.method && ["POST", "PUT", "PATCH"].includes(options.method)) {
47	    headers["Content-Type"] = "application/json";
48	  }
49	
50	  if (session?.agentId) {
51	    headers["X-Bayes-Agent-Id"] = session.agentId;
52	  }
53	
54	  const res = await fetch(`${API_BASE}${path}`, {
55	    ...options,
56	    headers,
57	  });
58	
59	  const body = await res.json();
60	
61	  if (!res.ok) {
62	    const err = body as ApiError;
63	    throw new BayesApiError(
64	      res.status,
65	      err.error?.code ?? "unknown_error",
66	      err.error?.details ?? {},
67	    );
68	  }
69	
70	  return body as T;
71	}
