73	export function listMarkets(
74	  filters: MarketListFilters = {},
75	): Promise<MarketListResponse> {
76	  const normalized = normalizeMarketListFilters(filters);
77	  const params = new URLSearchParams();
78	
79	  if (normalized.status) {
80	    params.set("status", normalized.status);
81	  }
82	
83	  if (normalized.sort) {
84	    params.set("sort", normalized.sort);
85	  }
86	
87	  if (normalized.q) {
88	    params.set("q", normalized.q);
89	  }
90	
91	  const qs = params.toString();
92	  return request<MarketListResponse>(`/v1/markets${qs ? `?${qs}` : ""}`);
93	}
